+static int         dir_is_empty(int dir_inum);
+static int         resolve_path(const char *pathname, int cwd_inum, int follow_last,
+                                int *parent_inum_out, char name_out[]);
+static int         resolve_path_sym(const char *pathname, int cwd_inum, int follow_last,
+                                    int *parent_inum_out, char name_out[], int depth);
+static int         get_client_cwd(int pid);
+static void        set_client_cwd(int pid, int cwd_inum);
+static int         alloc_fd(int pid, int inum, int reuse);
+static int         find_open(int pid, int fd);
+static void        close_fd(int pid, int fd);
+
+/* ============================================================
+ * Block cache operations
+ * ============================================================ */
+
+static char *
+get_block(int block_num)
+{
+    int i, oldest_idx, oldest_time;
+
+    /* Search cache */
+    for (i = 0; i < BLOCK_CACHESIZE; i++) {
+        if (bcache[i].valid && bcache[i].block_num == block_num) {
+            bcache[i].lru_time = ++g_lru_clock;
+            return bcache[i].data;
+        }
+    }
+
+    /* Find slot to evict (LRU) */
+    oldest_idx = 0;
+    oldest_time = bcache[0].valid ? bcache[0].lru_time : -1;
+    for (i = 1; i < BLOCK_CACHESIZE; i++) {
+        if (!bcache[i].valid) {
+            oldest_idx = i;
+            oldest_time = -1;
+            break;
+        }
+        if (bcache[i].lru_time < oldest_time) {
+            oldest_time = bcache[i].lru_time;
+            oldest_idx = i;
+        }
+    }
+
+    /* Write back dirty block if evicting */
+    if (bcache[oldest_idx].valid && bcache[oldest_idx].dirty) {
+        WriteSector(bcache[oldest_idx].block_num, bcache[oldest_idx].data);
+        bcache[oldest_idx].dirty = 0;
+    }
+
+    /* Load new block */
+    if (ReadSector(block_num, bcache[oldest_idx].data) != 0) {
+        return NULL;
+    }
+    bcache[oldest_idx].valid = 1;
+    bcache[oldest_idx].dirty = 0;
+    bcache[oldest_idx].block_num = block_num;
+    bcache[oldest_idx].lru_time = ++g_lru_clock;
+    return bcache[oldest_idx].data;
+}
+
+static void
+mark_block_dirty(int block_num)
+{
+    int i;
+    for (i = 0; i < BLOCK_CACHESIZE; i++) {
+        if (bcache[i].valid && bcache[i].block_num == block_num) {
+            bcache[i].dirty = 1;
+            return;
+        }
+    }
+}
+
+/* ============================================================
+ * Inode cache operations
+ * ============================================================ */
+
+static struct inode *
+get_inode(int inum)
+{
+    int i, oldest_idx, oldest_time;
+    int inode_block_num, inode_off;
+    char *blk;
+
+    if (inum <= 0 || inum > g_num_inodes)
+        return NULL;
+
+    /* Search cache */
+    for (i = 0; i < INODE_CACHESIZE; i++) {
+        if (icache[i].valid && icache[i].inum == inum) {
+            icache[i].lru_time = ++g_lru_clock;
+            return &icache[i].inode;
+        }
+    }
+
+    /* Find slot to evict (LRU) */
+    oldest_idx = 0;
+    oldest_time = icache[0].valid ? icache[0].lru_time : -1;
+    for (i = 1; i < INODE_CACHESIZE; i++) {
+        if (!icache[i].valid) {
+            oldest_idx = i;
+            oldest_time = -1;
+            break;
+        }
+        if (icache[i].lru_time < oldest_time) {
+            oldest_time = icache[i].lru_time;
+            oldest_idx = i;
+        }
+    }
+
+    /* Write back dirty inode if evicting */
+    if (icache[oldest_idx].valid && icache[oldest_idx].dirty) {
+        flush_inode(icache[oldest_idx].inum);
+    }
+
+    /* Load new inode from disk */
+    inode_block_num = 1 + inum / INODES_PER_BLOCK;
+    inode_off = (inum % INODES_PER_BLOCK) * INODESIZE;
+
+    blk = get_block(inode_block_num);
+    if (!blk)
+        return NULL;
+
+    memcpy(&icache[oldest_idx].inode, blk + inode_off, INODESIZE);
+    icache[oldest_idx].valid = 1;
+    icache[oldest_idx].dirty = 0;
+    icache[oldest_idx].inum = inum;
+    icache[oldest_idx].lru_time = ++g_lru_clock;
+    return &icache[oldest_idx].inode;
+}
+
+static void
+mark_inode_dirty(int inum)
+{
+    int i;
+    for (i = 0; i < INODE_CACHESIZE; i++) {
+        if (icache[i].valid && icache[i].inum == inum) {
+            icache[i].dirty = 1;
+            return;
+        }
+    }
+}
+
+static void
+flush_inode(int inum)
+{
+    int i;
+    int inode_block_num, inode_off;
+    char *blk;
+
+    for (i = 0; i < INODE_CACHESIZE; i++) {
+        if (icache[i].valid && icache[i].inum == inum) {
+            if (!icache[i].dirty)
+                return;
+            inode_block_num = 1 + inum / INODES_PER_BLOCK;
+            inode_off = (inum % INODES_PER_BLOCK) * INODESIZE;
+            blk = get_block(inode_block_num);
+            if (blk) {
+                memcpy(blk + inode_off, &icache[i].inode, INODESIZE);
+                mark_block_dirty(inode_block_num);
+            }
+            icache[i].dirty = 0;
+            return;
+        }
+    }
+}
+
+/* ============================================================
+ * Sync: flush all dirty data
+ * ============================================================ */
+
+static void
+sync_all(void)
+{
+    int i;
+
+    /* Flush dirty inodes first */
+    for (i = 0; i < INODE_CACHESIZE; i++) {
+        if (icache[i].valid && icache[i].dirty) {
+            flush_inode(icache[i].inum);
+        }
+    }
+
+    /* Flush dirty blocks */
+    for (i = 0; i < BLOCK_CACHESIZE; i++) {
+        if (bcache[i].valid && bcache[i].dirty) {
+            WriteSector(bcache[i].block_num, bcache[i].data);
+            bcache[i].dirty = 0;
+        }
+    }
+}
+
+/* ============================================================
+ * Block allocation
+ * ============================================================ */
+
+static int
+alloc_block(void)
+{
+    int block_num;
+    char *blk;
+
+    if (g_free_block_count <= 0)
+        return 0; /* disk full */
+
+    block_num = g_free_blocks[--g_free_block_count];
+
+    /* Zero out the new block */
+    blk = get_block(block_num);
+    if (blk) {
+        memset(blk, 0, SECTORSIZE);
+        mark_block_dirty(block_num);
+    }
+    return block_num;
+}
+
+static void
+free_block(int block_num)
+{
+    if (block_num <= 0 || block_num < g_first_data_block || block_num >= g_num_blocks)
+        return;
+    g_free_blocks[g_free_block_count++] = block_num;
+}
+
+/* ============================================================
+ * Inode allocation
+ * ============================================================ */
+
+static int
+alloc_inode(int type)
+{
+    int inum;
+    struct inode *inode;
+
+    if (g_free_inode_count <= 0)
+        return ERROR; /* no free inodes */
+
+    inum = g_free_inodes[--g_free_inode_count];
+
+    inode = get_inode(inum);
+    if (!inode)
+        return ERROR;
+
+    /* Initialize the inode */
+    inode->type = (short)type;
+    inode->nlink = 0;
+    inode->reuse++;
+    inode->size = 0;
+    memset(inode->direct, 0, sizeof(inode->direct));
+    inode->indirect = 0;
+    mark_inode_dirty(inum);
+
+    return inum;
+}
+
+static void
+free_inode_and_blocks(int inum)
+{
+    int i;
+    struct inode *inode;
+    char *ind_blk;
+    int *ind_entries;
+
+    inode = get_inode(inum);
+    if (!inode)
+        return;
+
+    /* Free all direct blocks */
+    for (i = 0; i < NUM_DIRECT; i++) {
+        if (inode->direct[i] != 0) {
+            free_block(inode->direct[i]);
+            inode->direct[i] = 0;
+        }
+    }
+
+    /* Free indirect blocks */
+    if (inode->indirect != 0) {
+        ind_blk = get_block(inode->indirect);
+        if (ind_blk) {
+            ind_entries = (int *)ind_blk;
+            for (i = 0; i < PTRS_PER_BLOCK; i++) {
+                if (ind_entries[i] != 0) {
+                    free_block(ind_entries[i]);
+                }
+            }
+        }
+        free_block(inode->indirect);
+        inode->indirect = 0;
+    }
+
+    /* Mark inode as free */
+    inode->type = INODE_FREE;
+    inode->nlink = 0;
+    inode->size = 0;
+    mark_inode_dirty(inum);
+
+    /* Return to free list */
+    g_free_inodes[g_free_inode_count++] = inum;
+}
+
+/* ============================================================
+ * File block mapping
+ * ============================================================ */
+
+/*
+ * Get the disk block number for block_idx-th block of a file.
+ * If create=1 and the block doesn't exist, allocate it.
+ * Returns block number (0 = hole/unallocated), or -1 on error.
+ */
+static int
+get_file_block(struct inode *inode, int inum, int block_idx, int create)
+{
+    char *ind_blk;
+    int *ind_entries;
+    int new_block;
+    int indirect_idx;
+
+    if (block_idx < NUM_DIRECT) {
+        if (inode->direct[block_idx] == 0 && create) {
+            new_block = alloc_block();
+            if (new_block == 0)
+                return -1; /* disk full */
+            inode->direct[block_idx] = new_block;
+            mark_inode_dirty(inum);
+        }
+        return inode->direct[block_idx];
+    }
+
+    /* Indirect block */
+    indirect_idx = block_idx - NUM_DIRECT;
+    if (indirect_idx >= PTRS_PER_BLOCK)
+        return -1; /* beyond max file size */
+
+    if (inode->indirect == 0) {
+        if (!create)
+            return 0;
+        new_block = alloc_block();
+        if (new_block == 0)
+            return -1;
+        inode->indirect = new_block;
+        mark_inode_dirty(inum);
+        /* block is already zeroed by alloc_block */
+    }
+
+    ind_blk = get_block(inode->indirect);
+    if (!ind_blk)
+        return -1;
+
+    ind_entries = (int *)ind_blk;
+    if (ind_entries[indirect_idx] == 0 && create) {
+        new_block = alloc_block();
+        if (new_block == 0)
+            return -1;
+        ind_entries[indirect_idx] = new_block;
+        mark_block_dirty(inode->indirect);
+    }
+    return ind_entries[indirect_idx];
+}
+
+/* ============================================================
+ * File I/O
+ * ============================================================ */
+
+static int
+file_read_data(int inum, int pos, char *buf, int len)
+{
+    struct inode *inode;
+    int total_read, block_idx, block_off, block_num, chunk;
+    char *blk;
+
+    inode = get_inode(inum);
+    if (!inode)
+        return ERROR;
+
+    if (pos >= inode->size || len <= 0)
+        return 0;
+
+    if (pos + len > inode->size)
+        len = inode->size - pos;
+
+    total_read = 0;
+    while (len > 0) {
+        block_idx = pos / BLOCKSIZE;
+        block_off = pos % BLOCKSIZE;
+        chunk = BLOCKSIZE - block_off;
+        if (chunk > len)
+            chunk = len;
+
+        /* Need to re-fetch inode since get_block might evict it */
+        inode = get_inode(inum);
+        if (!inode)
+            return ERROR;
+
+        block_num = get_file_block(inode, inum, block_idx, 0);
+        if (block_num == -1)
+            return ERROR;
+
+        if (block_num == 0) {
+            /* Hole: return zeros */
+            memset(buf + total_read, 0, chunk);
+        } else {
+            blk = get_block(block_num);
+            if (!blk)
+                return ERROR;
+            memcpy(buf + total_read, blk + block_off, chunk);
+        }
+
+        total_read += chunk;
+        pos += chunk;
+        len -= chunk;
+    }
+    return total_read;
+}
+
+static int
+file_write_data(int inum, int pos, const char *buf, int len)
+{
+    struct inode *inode;
+    int total_written, block_idx, block_off, block_num, chunk;
+    char *blk;
+
+    if (len <= 0)
+        return 0;
+
+    total_written = 0;
+    while (len > 0) {
+        block_idx = pos / BLOCKSIZE;
+        block_off = pos % BLOCKSIZE;
+        chunk = BLOCKSIZE - block_off;
+        if (chunk > len)
+            chunk = len;
+
+        /* Fetch inode fresh each iteration (cache evictions) */
+        inode = get_inode(inum);
+        if (!inode)
+            return ERROR;
+
+        block_num = get_file_block(inode, inum, block_idx, 1);
+        if (block_num <= 0)
+            return ERROR;
+
+        blk = get_block(block_num);
+        if (!blk)
+            return ERROR;
+        memcpy(blk + block_off, buf + total_written, chunk);
+        mark_block_dirty(block_num);
+
+        total_written += chunk;
+        pos += chunk;
+        len -= chunk;
+
+        /* Update file size */
+        inode = get_inode(inum);
+        if (!inode)
+            return ERROR;
+        if (pos > inode->size) {
+            inode->size = pos;
+            mark_inode_dirty(inum);
+        }
+    }
+    return total_written;
+}
+
+/*
+ * Zero out blocks in range [pos, size) to handle holes when seeking past EOF.
+ * Not strictly needed since holes naturally return zeros, but for gaps
+ * that require explicit zeroing (seek past EOF then write), we rely on
+ * alloc_block() zeroing new blocks.
+ */
+static void
+file_truncate(int inum)
+{
+    struct inode *inode;
+    int i;
+    char *ind_blk;
+    int *ind_entries;
+
+    inode = get_inode(inum);
+    if (!inode)
+        return;
+
+    /* Free all direct blocks */
+    for (i = 0; i < NUM_DIRECT; i++) {
+        if (inode->direct[i] != 0) {
+            free_block(inode->direct[i]);
+            inode->direct[i] = 0;
+        }
+    }
+
+    /* Free indirect blocks */
+    if (inode->indirect != 0) {
+        ind_blk = get_block(inode->indirect);
+        if (ind_blk) {
+            ind_entries = (int *)ind_blk;
+            for (i = 0; i < PTRS_PER_BLOCK; i++) {
+                if (ind_entries[i] != 0) {
+                    free_block(ind_entries[i]);
+                    ind_entries[i] = 0;
+                }
+            }
+        }
+        free_block(inode->indirect);
+        inode->indirect = 0;
+    }
+
+    inode = get_inode(inum);
+    if (inode) {
+        inode->size = 0;
+        mark_inode_dirty(inum);
+    }
+}
+
+/* ============================================================
+ * Directory operations
+ * ============================================================ */
+
+/*
+ * Look up a name in a directory.
+ * Returns the inum of the entry, or 0 if not found, or ERROR on error.
+ * If entry_offset is non-NULL, sets it to the byte offset in the directory.
+ */
+static int
+dir_lookup(int dir_inum, const char *name, int namelen, int *entry_offset)
+{
+    struct inode *inode;
+    struct dir_entry entry;
+    int pos, n;
+
+    if (namelen <= 0 || namelen > DIRNAMELEN)
+        return 0;
+
+    inode = get_inode(dir_inum);
+    if (!inode || inode->type != INODE_DIRECTORY)
+        return ERROR;
+
+    pos = 0;
+    while (pos < inode->size) {
+        n = file_read_data(dir_inum, pos, (char *)&entry, sizeof(entry));
+        if (n != (int)sizeof(entry))
+            break;
+
+        if (entry.inum != 0) {
+            int cmplen = namelen < DIRNAMELEN ? namelen : DIRNAMELEN;
+            if (memcmp(entry.name, name, cmplen) == 0) {
+                /* Check that the rest is zero (or name fills DIRNAMELEN) */
+                int ok = 1;
+                if (namelen < DIRNAMELEN && entry.name[namelen] != '\0')
+                    ok = 0;
+                if (ok) {
+                    if (entry_offset)
+                        *entry_offset = pos;
+                    return entry.inum;
+                }
+            }
+        }
+        pos += sizeof(entry);
+    }
+    return 0;
+}
+
+/*
+ * Add a directory entry to a directory.
+ * Reuses a free entry if available; otherwise appends.
+ * Returns 0 on success, ERROR on failure.
+ */
+static int
+dir_add_entry(int dir_inum, const char *name, int namelen, int entry_inum)
+{
+    struct inode *inode;
+    struct dir_entry entry;
+    int pos, n, free_pos;
+
+    if (namelen <= 0 || namelen > DIRNAMELEN)
+        return ERROR;
+
+    inode = get_inode(dir_inum);
+    if (!inode || inode->type != INODE_DIRECTORY)
+        return ERROR;
+
+    /* First pass: find a free slot */
+    free_pos = -1;
+    pos = 0;
+    while (pos < inode->size) {
+        n = file_read_data(dir_inum, pos, (char *)&entry, sizeof(entry));
+        if (n != (int)sizeof(entry))
+            break;
+        if (entry.inum == 0 && free_pos < 0) {
+            free_pos = pos;
+            break;
+        }
+        pos += sizeof(entry);
+    }
+
+    /* Build entry */
+    memset(&entry, 0, sizeof(entry));
+    entry.inum = (short)entry_inum;
+    memcpy(entry.name, name, namelen);
+
+    if (free_pos >= 0) {
+        /* Reuse free slot */
+        if (file_write_data(dir_inum, free_pos, (char *)&entry, sizeof(entry)) < 0)
+            return ERROR;
+    } else {
+        /* Append at end */
+        inode = get_inode(dir_inum);
+        if (!inode)
+            return ERROR;
+        pos = inode->size;
+        if (file_write_data(dir_inum, pos, (char *)&entry, sizeof(entry)) < 0)
+            return ERROR;
+    }
+    return 0;
+}
+
+/*
+ * Remove a directory entry (set inum to 0).
+ * Returns 0 on success, ERROR if not found.
+ */
+static int
+dir_remove_entry(int dir_inum, const char *name, int namelen)
+{
+    struct inode *inode;
+    struct dir_entry entry;
+    int pos, n;
+
+    if (namelen <= 0 || namelen > DIRNAMELEN)
+        return ERROR;
+
+    inode = get_inode(dir_inum);
+    if (!inode || inode->type != INODE_DIRECTORY)
+        return ERROR;
+
+    pos = 0;
+    while (pos < inode->size) {
+        n = file_read_data(dir_inum, pos, (char *)&entry, sizeof(entry));
+        if (n != (int)sizeof(entry))
+            break;
+
+        if (entry.inum != 0) {
+            int cmplen = namelen < DIRNAMELEN ? namelen : DIRNAMELEN;
+            if (memcmp(entry.name, name, cmplen) == 0) {
+                int ok = 1;
+                if (namelen < DIRNAMELEN && entry.name[namelen] != '\0')
+                    ok = 0;
+                if (ok) {
+                    entry.inum = 0;
+                    memset(entry.name, 0, DIRNAMELEN);
+                    if (file_write_data(dir_inum, pos, (char *)&entry, sizeof(entry)) < 0)
+                        return ERROR;
+                    return 0;
+                }
+            }
+        }
+        pos += sizeof(entry);
+    }
+    return ERROR;
+}
+
+/*
+ * Check if a directory is empty (only '.' and '..' entries, or free entries).
+ * Returns 1 if empty, 0 if not empty, ERROR on error.
+ */
+static int
+dir_is_empty(int dir_inum)
+{
+    struct inode *inode;
+    struct dir_entry entry;
+    int pos, n;
+
+    inode = get_inode(dir_inum);
+    if (!inode || inode->type != INODE_DIRECTORY)
+        return ERROR;
+
+    pos = 0;
+    while (pos < inode->size) {
+        n = file_read_data(dir_inum, pos, (char *)&entry, sizeof(entry));
+        if (n != (int)sizeof(entry))
+            break;
+
+        if (entry.inum != 0) {
+            /* Check for . and .. */
+            if (entry.name[0] == '.' && entry.name[1] == '\0')
+                goto next;
+            if (entry.name[0] == '.' && entry.name[1] == '.' && entry.name[2] == '\0')
+                goto next;
+            return 0; /* non-empty */
+        }
+next:
+        pos += sizeof(entry);
+    }
+    return 1;
+}
+
+/* ============================================================
+ * Pathname resolution
+ * ============================================================ */
+
+static int
+resolve_path_sym(const char *pathname, int cwd_inum, int follow_last,
+                 int *parent_inum_out, char name_out[], int depth)
+{
+    char path_buf[MAXPATHNAMELEN + 1];
+    char *comp, *next_sep;
+    int cur_inum, next_inum, parent_inum, namelen;
+    struct inode *inode;
+    char symlink_buf[MAXPATHNAMELEN + 1];
+    int symlink_len;
+
+    if (depth > MAXSYMLINKS)
+        return ERROR;
+
+    if (!pathname || pathname[0] == '\0')
+        return ERROR;
+
+    if ((int)strlen(pathname) >= MAXPATHNAMELEN)
+        return ERROR;
+
+    strncpy(path_buf, pathname, MAXPATHNAMELEN);
+    path_buf[MAXPATHNAMELEN] = '\0';
+
+    /* Determine starting inode */
+    if (path_buf[0] == '/') {
+        cur_inum = ROOTINODE;
+        comp = path_buf + 1;
+    } else {
+        cur_inum = cwd_inum;
+        comp = path_buf;
+    }
+
+    parent_inum = cur_inum;
+
+    /* Handle trailing slash: treat "/" as root directory */
+    if (*comp == '\0') {
+        /* Path is just "/" or was "/" */
+        if (parent_inum_out)
+            *parent_inum_out = cur_inum;
+        if (name_out)
+            name_out[0] = '\0';
+        return cur_inum;
+    }
+
+    while (*comp != '\0') {
+        /* Skip multiple slashes */
+        while (*comp == '/')
+            comp++;
+        if (*comp == '\0')
+            break;
+
+        /* Find end of this component */
+        next_sep = comp;
+        while (*next_sep != '\0' && *next_sep != '/')
+            next_sep++;
+
+        namelen = (int)(next_sep - comp);
+        if (namelen > DIRNAMELEN)
+            return ERROR; /* component too long */
+
+        int is_last = (*next_sep == '\0');
+
+        /* Handle . and .. */
+        if (namelen == 1 && comp[0] == '.') {
+            /* Current directory - no change */
+            if (is_last) {
+                if (parent_inum_out)
+                    *parent_inum_out = parent_inum;
+                if (name_out) {
+                    name_out[0] = '.';
+                    name_out[1] = '\0';
+                }
+                return cur_inum;
+            }
+            comp = next_sep;
+            if (*comp == '/') comp++;
+            continue;
+        }
+
+        if (namelen == 2 && comp[0] == '.' && comp[1] == '.') {
+            /* Parent directory */
+            inode = get_inode(cur_inum);
+            if (!inode || inode->type != INODE_DIRECTORY)
+                return ERROR;
+            int parent_of_cur = dir_lookup(cur_inum, "..", 2, NULL);
+            if (parent_of_cur <= 0)
+                parent_of_cur = cur_inum; /* at root, .. == . */
+            parent_inum = parent_of_cur;
+
+            if (is_last) {
+                /* Go to grandparent */
+                inode = get_inode(parent_of_cur);
+                if (!inode)
+                    return ERROR;
+                int grandparent = dir_lookup(parent_of_cur, "..", 2, NULL);
+                if (grandparent <= 0)
+                    grandparent = parent_of_cur;
+                if (parent_inum_out)
+                    *parent_inum_out = grandparent;
+                if (name_out) {
+                    name_out[0] = '.';
+                    name_out[1] = '.';
+                    name_out[2] = '\0';
+                }
+                cur_inum = parent_of_cur;
+                return cur_inum;
+            }
+            cur_inum = parent_of_cur;
+            comp = next_sep;
+            if (*comp == '/') comp++;
+            continue;
+        }
+
+        /* Look up this component in cur_inum directory */
+        inode = get_inode(cur_inum);
+        if (!inode || inode->type != INODE_DIRECTORY)
+            return ERROR;
+
+        parent_inum = cur_inum;
+        next_inum = dir_lookup(cur_inum, comp, namelen, NULL);
+
+        if (is_last) {
+            /* Last component */
+            if (parent_inum_out)
+                *parent_inum_out = cur_inum;
+            if (name_out) {
+                int copy_len = namelen < DIRNAMELEN ? namelen : DIRNAMELEN;
+                memcpy(name_out, comp, copy_len);
+                name_out[copy_len] = '\0';
+            }
+
+            if (next_inum <= 0) {
+                return 0; /* not found */
+            }
+
+            /* Check for symlink on last component */
+            if (follow_last) {
+                inode = get_inode(next_inum);
+                if (inode && inode->type == INODE_SYMLINK) {
+                    /* Follow symlink */
+                    symlink_len = inode->size;
+                    if (symlink_len >= MAXPATHNAMELEN)
+                        return ERROR;
+                    if (file_read_data(next_inum, 0, symlink_buf, symlink_len) != symlink_len)
+                        return ERROR;
+                    symlink_buf[symlink_len] = '\0';
+                    int sym_cwd = (symlink_buf[0] == '/') ? ROOTINODE : cur_inum;
+                    return resolve_path_sym(symlink_buf, sym_cwd, follow_last,
+                                            parent_inum_out, name_out, depth + 1);
+                }
+            }
+            return next_inum;
+        }
