+/* ============================================================
+ * Validation helpers
+ * ============================================================ */
+
+/*
+ * Validate a pathname argument: not NULL, not empty, not too long.
+ * Returns 0 if valid, -1 if invalid.
+ */
+static int
+valid_pathname(const void *ptr)
+{
+    const char *s = (const char *)ptr;
+    if (!s)
+        return -1;
+    if (s[0] == '\0')
+        return -1;
+    return 0;
+}
