+/* ============================================================
+ * Filesystem operation handlers
+ * ============================================================ */
+
+static int
+handle_open(int pid, int cwd_inum, const char *pathname)
+{
+    int inum;
+    struct inode *inode;
+    int fd;
+
+    if (!pathname || pathname[0] == '\0')
+        return ERROR;
+
+    inum = resolve_path(pathname, cwd_inum, 1, NULL, NULL);
+    if (inum <= 0)
+        return ERROR;
+
+    inode = get_inode(inum);
+    if (!inode)
+        return ERROR;
+
+    if (inode->type == INODE_FREE)
+        return ERROR;
+
+    fd = alloc_fd(pid, inum, inode->reuse);
+    if (fd == ERROR)
+        return ERROR;
+
+    return fd;
+}
+
+static int
+handle_close(int pid, int fd)
+{
+    int idx = find_open(pid, fd);
+    if (idx < 0)
+        return ERROR;
+    close_fd(pid, fd);
+    return 0;
+}
+
+static int
+handle_create(int pid, int cwd_inum, const char *pathname)
+{
+    int parent_inum, inum, fd;
+    char name[DIRNAMELEN + 1];
+    struct inode *inode;
+    int namelen;
+
+    if (!pathname || pathname[0] == '\0')
+        return ERROR;
+
+    /* Reject creating "." ".." "/" */
+    {
+        const char *p = pathname;
+        /* strip leading slashes */
+        while (*p == '/') p++;
+        if (*p == '\0') return ERROR; /* just "/" */
+        /* Check if the final component is "." or ".." */
+        const char *last = p;
+        while (*p) { if (*p == '/') last = p + 1; p++; }
+        if (strcmp(last, ".") == 0 || strcmp(last, "..") == 0)
+            return ERROR;
+    }
+
+    /* Try to resolve - might not exist yet */
+    parent_inum = 0;
+    name[0] = '\0';
+    inum = resolve_path(pathname, cwd_inum, 0, &parent_inum, name);
+    /* inum == 0 means not found (name & parent_inum set) */
+    /* inum == ERROR means parent doesn't exist */
+
+    if (inum == ERROR)
+        return ERROR;
+
+    if (parent_inum <= 0)
+        return ERROR;
+
+    namelen = (int)strlen(name);
+    if (namelen == 0 || namelen > DIRNAMELEN)
+        return ERROR;
+
+    if (inum > 0) {
+        /* File exists */
+        inode = get_inode(inum);
+        if (!inode)
+            return ERROR;
+        if (inode->type == INODE_DIRECTORY)
+            return ERROR; /* can't create over a directory */
+        if (inode->type == INODE_SYMLINK)
+            return ERROR; /* can't create over a symlink */
+        /* Truncate existing file */
+        file_truncate(inum);
+        inode = get_inode(inum);
+        if (!inode)
+            return ERROR;
+        /* Keep same inode, just reset */
+    } else {
+        /* Create new inode */
+        inum = alloc_inode(INODE_REGULAR);
+        if (inum == ERROR)
+            return ERROR;
+
+        /* Add entry to parent directory */
+        if (dir_add_entry(parent_inum, name, namelen, inum) < 0) {
+            free_inode_and_blocks(inum);
+            return ERROR;
+        }
+
+        inode = get_inode(inum);
+        if (!inode)
+            return ERROR;
+        inode->nlink = 1;
+        mark_inode_dirty(inum);
+    }
+
+    fd = alloc_fd(pid, inum, inode->reuse);
+    if (fd == ERROR)
+        return ERROR;
+
+    return fd;
+}
