+static int
+handle_read(int pid, int fd, void *buf_addr, int len)
+{
+    int idx, inum, pos, nread;
+    struct inode *inode;
+    char local_buf[BLOCKSIZE];
+    int total_read, chunk;
+    char *dst = (char *)buf_addr;
+
+    idx = find_open(pid, fd);
+    if (idx < 0)
+        return ERROR;
+
+    inum = g_open_table[idx].inum;
+    pos = g_open_table[idx].pos;
+
+    inode = get_inode(inum);
+    if (!inode || inode->type == INODE_FREE)
+        return ERROR;
+
+    /* Directories can be read but not written */
+    if (len <= 0)
+        return 0;
+
+    if (inode->type == INODE_REGULAR || inode->type == INODE_DIRECTORY) {
+        if (pos >= inode->size)
+            return 0;
+    }
+
+    /* Read in chunks and CopyTo client */
+    total_read = 0;
+    while (len > 0) {
+        chunk = len < BLOCKSIZE ? len : BLOCKSIZE;
+        nread = file_read_data(inum, pos, local_buf, chunk);
+        if (nread <= 0)
+            break;
+        if (CopyTo(pid, (char *)dst + total_read, local_buf, nread) != 0)
+            return ERROR;
+        total_read += nread;
+        pos += nread;
+        len -= nread;
+        if (nread < chunk)
+            break; /* EOF */
+    }
+
+    g_open_table[idx].pos = pos;
+    return total_read;
+}
+
+static int
+handle_write(int pid, int fd, const void *buf_addr, int len)
+{
+    int idx, inum, pos, nwritten;
+    struct inode *inode;
+    char local_buf[BLOCKSIZE];
+    int total_written, chunk;
+    const char *src = (const char *)buf_addr;
+
+    idx = find_open(pid, fd);
+    if (idx < 0)
+        return ERROR;
+
+    inum = g_open_table[idx].inum;
+    pos = g_open_table[idx].pos;
+
+    inode = get_inode(inum);
+    if (!inode || inode->type == INODE_FREE)
+        return ERROR;
+
+    /* Can't write to directories */
+    if (inode->type == INODE_DIRECTORY)
+        return ERROR;
+
+    if (len <= 0)
+        return 0;
+
+    /* Write in chunks, CopyFrom client */
+    total_written = 0;
+    while (len > 0) {
+        chunk = len < BLOCKSIZE ? len : BLOCKSIZE;
+        if (CopyFrom(pid, local_buf, (char *)src + total_written, chunk) != 0)
+            return ERROR;
+        nwritten = file_write_data(inum, pos, local_buf, chunk);
+        if (nwritten <= 0)
+            break;
+        total_written += nwritten;
+        pos += nwritten;
+        len -= nwritten;
+    }
+
+    g_open_table[idx].pos = pos;
+    return total_written;
+}
