+static int
+handle_seek(int pid, int fd, int offset, int whence)
+{
+    int idx, inum, pos, new_pos;
+    struct inode *inode;
+
+    idx = find_open(pid, fd);
+    if (idx < 0)
+        return ERROR;
+
+    inum = g_open_table[idx].inum;
+    pos = g_open_table[idx].pos;
+
+    inode = get_inode(inum);
+    if (!inode || inode->type == INODE_FREE)
+        return ERROR;
+
+    switch (whence) {
+    case SEEK_SET:
+        new_pos = offset;
+        break;
+    case SEEK_CUR:
+        new_pos = pos + offset;
+        break;
+    case SEEK_END:
+        new_pos = inode->size + offset;
+        break;
+    default:
+        return ERROR;
+    }
+
+    if (new_pos < 0)
+        return ERROR;
+
+    g_open_table[idx].pos = new_pos;
+    return new_pos;
+}
